struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) return false;
  auto conn = conn_result.value();

  // Create table if it doesn't exist
  create_table<Product>(conn);

  // Begin transaction
  auto begin_result = begin_transaction(conn);
  if (!begin_result) return false;
  auto transaction = begin_result.value();

  // Process each product update
  for (const auto& [product_id, quantity] : received) {
    // Build the update statement using sqlgen's fluent interface
    auto update_stmt = update<Product>("stock"_c.set("stock"_c + quantity))
                       | where("product_id"_c == product_id);

    // Execute the update statement
    auto exec_result = exec(transaction, update_stmt);
    if (!exec_result) {
      // Rollback on failure
      rollback(transaction);
      return false;
    }
  }

  // Commit transaction on success
  auto commit_result = commit(transaction);
  return commit_result.has_value();
}

}  // namespace update_inventory_stock
