#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
