};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen::literals;

  // Connect to the database
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build the query using sqlgen's fluent interface
  auto query = sqlgen::read<std::vector<Stats>>
               | sqlgen::select_from<Post>(
                    "user_id"_t1, 
                    "name"_t2, 
                    sqlgen::count().as<"post_count">(), 
                    sqlgen::avg(sqlgen::length("content"_t1)).as<"avg_length">()
                  )
               | sqlgen::join<User>("user_id"_t1 == "user_id"_t2)
               | sqlgen::group_by("user_id"_t1, "name"_t2);

  // Execute the query and return the result
  return query(conn).value();
}

}  // namespace group_by_with_aggregations
```

## Explanation:

1. **Database Connection**: Uses `sqlgen::sqlite::connect("test_db.sqlite")` to establish a connection to the SQLite database.

2. **Query Construction**: Builds the SQL query using sqlgen's fluent interface with the `|` operator:
   - `sqlgen::read<std::vector<Stats>>` specifies we want to read into a vector of Stats objects
   - `sqlgen::select_from<Post>` starts the query from the Post table
   - `"user_id"_t1` and `"name"_t2` select specific columns using table aliases
   - `sqlgen::count().as<"post_count">()` computes the COUNT aggregation and aliases it
   - `sqlgen::avg(sqlgen::length("content"_t1)).as<"avg_length">()` computes the AVG(LENGTH(content)) aggregation
   - `sqlgen::join<User>("user_id"_t1 == "user_id"_t2)` joins with the User table on user_id
   - `sqlgen::group_by("user_id"_t1, "name"_t2)` groups by user_id and name

3. **Query Execution**: Calls the query with the connection and extracts the result using `.value()`.

The query effectively implements:
```sql
SELECT u.user_id, u.name, COUNT(*) AS post_count, AVG(LENGTH(p.content)) AS avg_length
FROM Post p
JOIN User u ON p.user_id = u.user_id
GROUP BY u.user_id, u.name
