#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace create_table_as_select {

struct Source {
  sqlgen::PrimaryKey<int> id;
  int value;
};

struct Target {
  int value;
};

/**
 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
    using namespace sqlgen::literals;

    // Create a SELECT query from Source table with value > 100 condition
    auto select_query = sqlgen::select_from<Source>("value"_c) 
                      | sqlgen::where("value"_c > 100);

    // Create a table Target from the select query
    return sqlgen::create_as<Target>(select_query);
}

}  // namespace create_table_as_select
```

## Explanation:

1. **Namespace Usage**: The function uses `sqlgen::literals` namespace to enable the `_c` literal operator for column names.

2. **SELECT Query Construction**:
   - `sqlgen::select_from<Source>("value"_c)` creates a SELECT query targeting the `Source` table, selecting only the `value` column
   - The `_c` literal operator converts the string "value" into a column reference

3. **WHERE Condition**:
   - `sqlgen::where("value"_c > 100)` applies the filter condition using the `>` operator
   - The `operator|` chains the WHERE clause to the SELECT query

4. **CREATE TABLE AS**:
   - `sqlgen::create_as<Target>(select_query)` creates a table `Target` from the filtered SELECT query
   - The `Target` struct defines the structure of the new table

5. **Return Value**: The function returns the constructed query object, which can be executed against a database connection.

This implementation follows the sqlgen principles of using fluent interface with operator overloading (`|`) to build SQL queries in a type-safe manner.

